import{_ as a,p as e,q as i,a1 as r}from"./framework-caba6eb2.js";const t={},d=r('<h1 id="运动场馆" tabindex="-1"><a class="header-anchor" href="#运动场馆" aria-hidden="true">#</a> 运动场馆</h1><div class="custom-container tip"><p class="custom-container-title">版本要求</p><p>iOS: 1.3.2 (build &gt;= 96)</p><p>Android: 1.4.3</p></div><p>你可以通过Ham预定运动场馆</p><h2 id="准备使用" tabindex="-1"><a class="header-anchor" href="#准备使用" aria-hidden="true">#</a> 准备使用</h2><p>在使用预定场馆前，你需要在&quot;我的&quot;-&quot;信息门户设置&quot;中登录自己的信息门户账号</p><h2 id="查看场馆" tabindex="-1"><a class="header-anchor" href="#查看场馆" aria-hidden="true">#</a> 查看场馆</h2><p>在查看场馆中预定，你可以选择自己的目标运动、场馆，再查看空余的场次和时间段进行预定</p><p>查看场馆预定适用的情况：</p><ul><li>你某一天突然想去运动但没有预定</li><li>某个场馆预定的余量充足</li></ul><h2 id="设定收藏预定" tabindex="-1"><a class="header-anchor" href="#设定收藏预定" aria-hidden="true">#</a> 设定收藏预定</h2><p>你可以在设置中设置自己收藏的场馆、场次和时间段。设定后，该预定会出现在首页中方便你快速预定，同时你也可以通过Siri捷径进行自动化预定。</p><div class="custom-container tip"><p class="custom-container-title">提示</p><p>在首页快速预定或使用Siri捷径自动化预定时并不能确定该时间段下场次的空闲情况。当在该场次的预定失败后，Ham会自动选择相邻空闲的场次进行预定。</p></div><h2 id="订单中心" tabindex="-1"><a class="header-anchor" href="#订单中心" aria-hidden="true">#</a> 订单中心</h2><p>在首页中，你可以前往订单中心，查看或取消自己的订单。</p><h2 id="支付订单" tabindex="-1"><a class="header-anchor" href="#支付订单" aria-hidden="true">#</a> 支付订单</h2><p>在预定成功且到达支付时间时，你可以通过两种方式支付该订单：</p><ul><li>通过微信小程序预定：</li></ul><p>在&quot;场馆预约&quot;小程序中支付。该选项可以使用微信支付</p><ul><li>在网页内支付</li></ul><p>在确认信息后，Ham会提供给你一个链接。该链接为学校支付平台官方链接。你需要将它复制到浏览器中完成支付。该选项可以使用支付宝或云闪付支付。</p><div class="custom-container warning"><p class="custom-container-title">重要</p><p>你在武汉大学支付平台的支付与Ham无关</p></div><h2 id="预定状态" tabindex="-1"><a class="header-anchor" href="#预定状态" aria-hidden="true">#</a> 预定状态</h2><p>你的预定状态将会在首页展示。</p><p>在到达支付时间后，你可以在预定状态卡片中进行支付。</p><h2 id="自动化" tabindex="-1"><a class="header-anchor" href="#自动化" aria-hidden="true">#</a> 自动化</h2><p>使用Siri捷径进行自动化预定。</p>',26),h=[d];function n(c,s){return e(),i("div",null,h)}const o=a(t,[["render",n],["__file","sport.html.vue"]]);ex